+        if n == 0 {
+            break;
+        }
+        if decompressed.len() + n > max_bytes {
+            return Err(IoError::CompressionError(format!(
+                "Decompressed data exceeds size limit of {} bytes (possible decompression bomb)",
+                max_bytes
+            )));
+        }
+        decompressed.extend_from_slice(&buf[..n]);
+    }
+
     Ok(decompressed)
 }

